import { useState } from "react";
import axios from "axios";

const API = "http://localhost:5000";

export default function App() {
  const [email, setEmail] = useState("");
  const [apiKey, setApiKey] = useState("");
  const [usage, setUsage] = useState([]);
  const [response, setResponse] = useState("");
  const [rateLimitHit, setRateLimitHit] = useState(false);

  const signup = async () => {
    const res = await axios.post(`${API}/auth/signup`, { email });
    setApiKey(res.data.apiKey);
  };

  const callAPI = async () => {
    if (usage.length >= 5) {
      setRateLimitHit(true);
      return;
    }

    const res = await axios.get(
      `${API}/proxy?url=https://jsonplaceholder.typicode.com/todos/1&apiKey=${apiKey}`
    );

    setResponse(JSON.stringify(res.data, null, 2));
    setRateLimitHit(false);
  };

  const fetchUsage = async () => {
    const res = await axios.get(`${API}/usage/${apiKey}`);
    setUsage(res.data);
  };

  const billing = (usage.length * 0.2).toFixed(2);

  return (
    <div style={styles.container}>

      {/* Sidebar */}
      <div style={styles.sidebar}>
        <h2>🚀 MeterFlow</h2>
        <p>Dashboard</p>
        <p>API Keys</p>
        <p>Usage</p>
        <p>Billing</p>
      </div>

      {/* Main */}
      <div style={styles.main}>

        {/* Header */}
        <h1 style={{ marginBottom: "20px" }}>Developer Dashboard</h1>

        {/* Cards */}
        <div style={styles.cards}>
          <div style={styles.card}>
            <h4>Total Requests</h4>
            <h2>{usage.length}</h2>
          </div>

          <div style={styles.card}>
            <h4>Rate Limit</h4>
            <h2 style={{ color: rateLimitHit ? "red" : "green" }}>
              {rateLimitHit ? "Limit Hit" : "Active"}
            </h2>
          </div>

          <div style={styles.card}>
            <h4>Billing</h4>
            <h2>₹{billing}</h2>
          </div>
        </div>

        {/* API Key */}
        <div style={styles.section}>
          <h3>Generate API Key</h3>
          <input
            placeholder="Enter email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            style={styles.input}
          />
          <button style={styles.btnBlue} onClick={signup}>
            Generate
          </button>

          {apiKey && <div style={styles.key}>{apiKey}</div>}
        </div>

        {/* API Playground */}
        {apiKey && (
          <div style={styles.section}>
            <h3>API Playground</h3>

            <button style={styles.btnGreen} onClick={callAPI}>
              Call API
            </button>

            <button style={styles.btnPurple} onClick={fetchUsage}>
              Load Usage
            </button>

            {rateLimitHit && (
              <p style={{ color: "red" }}>
                ⚠ Rate limit exceeded (5 requests max)
              </p>
            )}

            {response && <pre style={styles.pre}>{response}</pre>}
          </div>
        )}

        {/* Usage Table */}
        {usage.length > 0 && (
          <div style={styles.section}>
            <h3>Usage Logs</h3>
            <table style={styles.table}>
              <thead>
                <tr>
                  <th>URL</th>
                  <th>Status</th>
                  <th>Time</th>
                </tr>
              </thead>
              <tbody>
                {usage.map((u, i) => (
                  <tr key={i}>
                    <td>{u.url}</td>
                    <td>{u.status}</td>
                    <td>{new Date(u.timestamp).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

      </div>
    </div>
  );
}

const styles = {
  container: { display: "flex", height: "100vh", fontFamily: "Arial" },
  sidebar: {
    width: "220px",
    background: "#0f172a",
    color: "white",
    padding: "20px",
  },
  main: {
    flex: 1,
    padding: "20px",
    background: "#f1f5f9",
    overflow: "auto",
  },
  cards: { display: "flex", gap: "15px", marginBottom: "20px" },
  card: {
    background: "white",
    padding: "15px",
    borderRadius: "8px",
    flex: 1,
    boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
  },
  section: {
    background: "white",
    padding: "20px",
    marginBottom: "20px",
    borderRadius: "8px",
  },
  input: { padding: "8px", marginRight: "10px" },
  key: { marginTop: "10px", background: "#eee", padding: "10px" },
  btnBlue: { background: "#2563eb", color: "white", padding: "8px", border: "none" },
  btnGreen: { background: "#16a34a", color: "white", padding: "8px", border: "none", marginRight: "10px" },
  btnPurple: { background: "#7c3aed", color: "white", padding: "8px", border: "none" },
  pre: { background: "black", color: "#0f0", padding: "10px", marginTop: "10px" },
  table: { width: "100%", borderCollapse: "collapse" },
};
